import React from 'react';

export const LOGO_BASE64 = "data:image/png;base64,";

interface LogoProps {
  size?: number;
  className?: string;
  style?: React.CSSProperties;
}

export function Logo({ size = 32, className = "", style = {} }: LogoProps) {
  return (
    <img
      src={LOGO_BASE64}
      alt="Controlla Logo"
      className={className}
      style={{
        width: size,
        height: size,
        objectFit: 'contain',
        flex: 'none',
        ...style
      }}
    />
  );
}
